-- 3) Skill / Movement Intelligence phase profiles
INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
  freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling
)
SELECT e.id, sp.id, 5, 'primary', m.slot, pos.order_index,
  FALSE, 1, 1, 2, m.impact, 'low'
FROM (VALUES
  ('hollow-body-hold', 'hollow_shape', 0),
  ('arch-body-hold', 'arch_shape', 0),
  ('hollow-to-arch-roll', 'shape_transition', 0),
  ('tuck-hold-rock', 'tuck_shape', 0),
  ('pike-fold-tall-sit', 'pike_shape', 0),
  ('straddle-sit-reach-lift', 'straddle_shape', 0),
  ('front-support-shape-hold', 'support_shape', 0),
  ('rear-support-shape-hold', 'support_shape', 0),
  ('wall-body-line-drill', 'line_drill', 0),
  ('stick-to-shape-freeze-game', 'shape_reaction', 0),
  ('log-roll', 'rolling_foundation', 1),
  ('egg-roll', 'rolling_foundation', 1),
  ('rock-and-roll-to-stand', 'roll_to_stand', 1),
  ('forward-roll-progression', 'forward_roll', 1),
  ('backward-roll-progression', 'backward_roll', 1),
  ('shoulder-roll-progression', 'shoulder_roll', 1),
  ('donkey-kick', 'hand_support_inversion', 1),
  ('wall-walk-handstand-line', 'handstand_line', 0),
  ('handstand-kick-up-wall', 'handstand_entry', 0),
  ('cartwheel', 'cartwheel_foundation', 1),
  ('cartwheel-step-over', 'cartwheel_foundation', 1),
  ('cartwheel-finish-lunge', 'cartwheel_finish', 1),
  ('round-off', 'roundoff_foundation', 1),
  ('hurdle-step-lunge', 'hurdle_entry', 1),
  ('wall-drill-split-shin-hold', 'sprint_iso', 0),
  ('wall-drill-march', 'sprint_mechanics', 0),
  ('wall-drill-switch', 'sprint_mechanics', 0),
  ('a-march', 'technical_march', 0),
  ('a-skip', 'sprint_rhythm', 0),
  ('ankling-dribble-march', 'foot_strike_skill', 0),
  ('straight-leg-bound-march', 'frontside_mechanics', 0),
  ('falling-start-hold', 'acceleration_position', 0),
  ('two-point-start-walk-in', 'acceleration_entry', 0),
  ('arm-action-drill', 'arm_action', 0),
  ('beam-walk', 'narrow_base_balance', 0),
  ('single-leg-balance-clock', 'single_leg_balance_skill', 0),
  ('cross-crawl-march', 'cross_body_coordination', 0),
  ('skipping-rhythm-drill', 'rhythm_locomotion', 0),
  ('carioca-walkthrough', 'transverse_coordination', 0),
  ('lateral-shuffle-walkthrough', 'lateral_movement_skill', 0),
  ('backpedal-walkthrough', 'backward_locomotion', 0),
  ('ladder-in-in-out-out', 'footwork_rhythm', 0),
  ('ladder-ickey-shuffle', 'footwork_rhythm', 0),
  ('low-hurdle-step-over', 'step_over_coordination', 0),
  ('mirror-shuffle-drill', 'mirror_reaction', 0),
  ('coach-point-and-go', 'visual_reaction', 0),
  ('colored-cone-call-out', 'visual_decision', 0),
  ('ball-drop-reaction', 'object_reaction', 0),
  ('partner-shadow-tag', 'movement_game', 0),
  ('gate-reaction-drill', 'reactive_start', 0)
) AS m(slug, slot, impact)
JOIN coaching.exercise e ON e.slug = m.slug
JOIN coaching.session_phase sp ON sp.key = 'skill_movement_intelligence'
JOIN coaching.phase_order_slot pos ON pos.key = m.slot
ON CONFLICT (exercise_id, phase_id) DO UPDATE SET
  role = EXCLUDED.role, order_slot = EXCLUDED.order_slot, fit_weight = EXCLUDED.fit_weight,
  impact_level = EXCLUDED.impact_level, intensity_ceiling = EXCLUDED.intensity_ceiling;

-- 4) Dosage profiles
