  ('backward-roll-progression', 'reps', 1, 8, NULL, 20, 30),
  ('shoulder-roll-progression', 'reps', 1, 8, NULL, 20, 30),
  ('donkey-kick', 'reps', 1, 8, NULL, 20, 30),
  ('wall-walk-handstand-line', 'reps', 1, 8, NULL, 20, 30),
  ('handstand-kick-up-wall', 'reps', 1, 8, NULL, 20, 30),
  ('cartwheel', 'reps', 1, 8, NULL, 20, 30),
  ('cartwheel-step-over', 'reps', 1, 8, NULL, 20, 30),
  ('cartwheel-finish-lunge', 'reps', 1, 8, NULL, 20, 30),
  ('round-off', 'reps', 1, 8, NULL, 20, 30),
  ('hurdle-step-lunge', 'reps', 1, 8, NULL, 20, 30),
  ('wall-drill-split-shin-hold', 'seconds', 2, NULL, 30, 20, 35),
  ('wall-drill-march', 'reps', 1, 8, NULL, 20, 30),
  ('wall-drill-switch', 'reps', 1, 8, NULL, 20, 30),
  ('a-march', 'reps', 1, 8, NULL, 20, 30),
  ('a-skip', 'reps', 1, 8, NULL, 20, 30),
  ('ankling-dribble-march', 'reps', 1, 8, NULL, 20, 30),
  ('straight-leg-bound-march', 'reps', 1, 8, NULL, 20, 30),
  ('falling-start-hold', 'seconds', 2, NULL, 30, 20, 35),
  ('two-point-start-walk-in', 'reps', 1, 8, NULL, 20, 30),
  ('arm-action-drill', 'reps', 1, 8, NULL, 20, 30),
  ('beam-walk', 'reps', 1, 8, NULL, 20, 30),
  ('single-leg-balance-clock', 'reps', 1, 8, NULL, 20, 30),
  ('cross-crawl-march', 'reps', 1, 8, NULL, 20, 30),
  ('skipping-rhythm-drill', 'reps', 1, 8, NULL, 20, 30),
  ('carioca-walkthrough', 'reps', 1, 8, NULL, 20, 30),
  ('lateral-shuffle-walkthrough', 'reps', 1, 8, NULL, 20, 30),
  ('backpedal-walkthrough', 'reps', 1, 8, NULL, 20, 30),
  ('ladder-in-in-out-out', 'reps', 1, 8, NULL, 20, 30),
  ('ladder-ickey-shuffle', 'reps', 1, 8, NULL, 20, 30),
  ('low-hurdle-step-over', 'reps', 1, 8, NULL, 20, 30),
  ('mirror-shuffle-drill', 'reps', 1, 8, NULL, 20, 30),
  ('coach-point-and-go', 'reps', 1, 8, NULL, 20, 30),
  ('colored-cone-call-out', 'reps', 1, 8, NULL, 20, 30),
  ('ball-drop-reaction', 'reps', 1, 8, NULL, 20, 30),
  ('partner-shadow-tag', 'reps', 1, 8, NULL, 20, 30),
  ('gate-reaction-drill', 'reps', 1, 8, NULL, 20, 30)
) AS m(slug, unit, sets, reps, work, rest, est)
JOIN coaching.exercise e ON e.slug = m.slug
WHERE NOT EXISTS (SELECT 1 FROM coaching.exercise_dosage_profile d WHERE d.exercise_id = e.id AND d.profile_name = 'Default');

