-- 8) Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary, what_it_is, why_it_matters,
  why_it_goes_here, programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name,
  e.card_summary,
  COALESCE(e.description, e.name),
  'Develops movement skill and body intelligence while the athlete is fresh.',
  CASE e.phase_subrole
    WHEN 'shape_position_intelligence' THEN 'Belongs in Shape & Position Intelligence — teaches body lines, shapes, and trunk control before dynamic skill.'
    WHEN 'rotation_inversion_tumbling_foundations' THEN 'Belongs in Rotation / Inversion / Tumbling Foundations — builds rolling, inversion, and tumbling prerequisites while fresh.'
    WHEN 'locomotion_sprint_mechanics' THEN 'Belongs in Locomotion & Sprint Mechanics — develops posture, rhythm, and acceleration shapes before speed output.'
    WHEN 'balance_coordination_rhythm' THEN 'Belongs in Balance / Coordination / Rhythm — develops timing, foot placement, and low-fatigue coordination.'
    WHEN 'perception_action_reactive_movement' THEN 'Belongs in Perception-Action / Reactive Movement — couples decision-making with movement under external cues.'
    ELSE 'Place in Skill / Movement Intelligence while fresh.'
  END,
  'Use in Skill phase after Prepare; scale volume by age and attention. Stop before fatigue.',
  'Do not use as conditioning or max-effort output work in the skill block.',
  'Reduce reps, duration, or range for youth and beginners.'
FROM coaching.exercise e
WHERE e.slug IN ('hollow-body-hold', 'arch-body-hold', 'hollow-to-arch-roll', 'tuck-hold-rock', 'pike-fold-tall-sit', 'straddle-sit-reach-lift', 'front-support-shape-hold', 'rear-support-shape-hold', 'wall-body-line-drill', 'stick-to-shape-freeze-game', 'log-roll', 'egg-roll', 'rock-and-roll-to-stand', 'forward-roll-progression', 'backward-roll-progression', 'shoulder-roll-progression', 'donkey-kick', 'wall-walk-handstand-line', 'handstand-kick-up-wall', 'cartwheel', 'cartwheel-step-over', 'cartwheel-finish-lunge', 'round-off', 'hurdle-step-lunge', 'wall-drill-split-shin-hold', 'wall-drill-march', 'wall-drill-switch', 'a-march', 'a-skip', 'ankling-dribble-march', 'straight-leg-bound-march', 'falling-start-hold', 'two-point-start-walk-in', 'arm-action-drill', 'beam-walk', 'single-leg-balance-clock', 'cross-crawl-march', 'skipping-rhythm-drill', 'carioca-walkthrough', 'lateral-shuffle-walkthrough', 'backpedal-walkthrough', 'ladder-in-in-out-out', 'ladder-ickey-shuffle', 'low-hurdle-step-over', 'mirror-shuffle-drill', 'coach-point-and-go', 'colored-cone-call-out', 'ball-drop-reaction', 'partner-shadow-tag', 'gate-reaction-drill')
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

